-- ── 1. Recreate the dropped schema ───────────────────────────────────
CREATE TABLE IF NOT EXISTS public.project_budget_items (
    id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    tenant_id   UUID NOT NULL REFERENCES public.tenants(id) ON DELETE CASCADE,
    site_id     UUID NOT NULL REFERENCES public.sites(id)   ON DELETE CASCADE,
    idx         INTEGER NOT NULL,
    label       TEXT,
    amount      NUMERIC(14, 2),
    created_at  TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at  TIMESTAMPTZ NOT NULL DEFAULT now(),
    CONSTRAINT chk_project_budget_idx CHECK (idx BETWEEN 1 AND 11),
    CONSTRAINT uq_project_budget_item_site_idx UNIQUE (site_id, idx)
);
CREATE INDEX IF NOT EXISTS idx_project_budget_items_site ON public.project_budget_items (site_id);

ALTER TABLE public.project_reviews
    ADD COLUMN IF NOT EXISTS budget_status TEXT NOT NULL DEFAULT 'draft',
    ADD COLUMN IF NOT EXISTS budget_total NUMERIC(14, 2),
    ADD COLUMN IF NOT EXISTS total_indoor_area_sqft NUMERIC(12, 2),
    ADD COLUMN IF NOT EXISTS total_area_sqft NUMERIC(12, 2),
    ADD COLUMN IF NOT EXISTS covers INTEGER,
    ADD COLUMN IF NOT EXISTS budget_supervisor_comments TEXT,
    ADD COLUMN IF NOT EXISTS budget_admin_comments TEXT;
ALTER TABLE public.project_reviews DROP CONSTRAINT IF EXISTS chk_project_budget_status;
ALTER TABLE public.project_reviews ADD CONSTRAINT chk_project_budget_status
    CHECK (budget_status IN ('draft','pending_supervisor','pending_admin','approved','rejected'));


